mapper.select:
SELECT id, register_id, doctor_id, title, dify_conversation_id, created_at, updated_at
FROM physician_ai_chat_session
WHERE id = #{id}

mapper.insert:
INSERT INTO physician_ai_chat_session (
    register_id, doctor_id, title, created_at, updated_at
) VALUES (
    #{registerId}, #{doctorId}, #{title},
    COALESCE(#{createdAt}, NOW()), COALESCE(#{updatedAt}, NOW())
)

mapper.update:
UPDATE physician_ai_chat_session
SET title = #{title}, updated_at = NOW()
WHERE id = #{id}

UPDATE physician_ai_chat_session
SET updated_at = NOW()
WHERE id = #{id}

UPDATE physician_ai_chat_session
SET dify_conversation_id = #{difyConversationId}, updated_at = NOW()
WHERE id = #{id}

UPDATE physician_ai_chat_session
SET dify_conversation_id = NULL, updated_at = NOW()
WHERE id = #{id}
